const ICO_HOUSE = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round"><path d="M3 11.4 12 4l9 7.4"/><path d="M5 10.2V20h14v-9.8"/><path d="M9.8 20v-5h4.4v5"/></svg>';
