    const esc = jogBackEscape(cs, card);
    if (esc === 'filter') { cs.filterTerms = (cs.filterTerms || []).filter((t) => t.g); cs.search = ''; afterFilterChange(card); }   // keep graph-view (.g) terms; clear only the fleet/search filter
