      + `<div class="ag-pcell"><div class="ag-pcap">Signature</div>${signingSignatureSrc(sg) ? `<img class="ag-sigthumb" src="${esc(signingSignatureSrc(sg))}" alt="signature on file">` : '<div class="ag-sigthumb"></div>'}</div>`
      + `</div>`
