  return `<div class="section inv-sec" data-cust="${esc(c.customerId)}"><h4>${toggle}</h4>`
    + (allInvs.length ? invSummaryStrip(allInvs, c) : '')
    + `<div class="inv-scroll${openId ? ' expanded' : ''}">${body}</div>`
    + addPill
