/** R1: funnel-stage gate (§7.1). */
function funnelPill(custId, which, stage) {
  const st = getStatus('funnelStage', stage);
  return `<span class="pill gate c-${st.color} js-funnel" data-r="R1" data-rec="${esc(custId)}" data-which="${which}">${I.chev}${esc(st.label)}</span>`;
}
/** R4: a DERIVED pill — rides another pill in the same section; no bg/border,
 *  destination icon + ink color only; sits directly RIGHT of its parent. */
function dPill(label, color, { card, recId, icon, title, alert } = {}) {
  const nav = card ? ` data-pill-card="${card}" data-pill-rec="${esc(recId)}"` : '';
  const ic = icon || (card ? CARD_ICON[card] : '') || '';
  const chat = (card && recId != null) ? ` data-chat-el data-chat-label="${esc(label)}" data-chat-color="${esc(color)}" data-chat-card="${esc(card)}" data-chat-rec="${esc(recId)}"` : '';   // §17 — category/derived pill → chat-draggable
  return `<span class="pill dvd c-${color}${alert ? ' alert' : ''}" data-r="${alert ? 'R4b' : 'R4'}"${nav}${chat}${title ? ` data-tip="${esc(title)}"` : ''}>${ic}<span class="t">${esc(label)}</span></span>`;
}
/** R5: the ADD affordance — dashed, "+Thing" (never the word "Add", never a
 *  space after +). `link:true` = orange ink (creates/links a record);
 *  `anchor:true` = the neon-blue +Part/Task variant. */
function addBtn(label, { js, data, link, line, anchor, h, icon } = {}) {
  // R5 RETIRED (Jac 2026-06-13): record-linking adds now wear R5b's BLUE anchor too.
  // R5b = BLUE dashed “+Thing” (links/creates a record OR adds a line item) ·
  // R5c = GRAY dashed “+Thing” (a normal empty field).
  const blue = link || line || anchor;
  const cls = `add-field${blue ? ' anchor' : ''}${js ? ' ' + js : ''}`;
  const rule = blue ? 'R5b' : 'R5c';
  return `<button class="${cls}" data-r="${rule}"${dataAttrs(data)}${h ? ` style="height:${h}px"` : ''}>${icon || ''}+${esc(label.replace(/^\+?\s*(Add\s+)?/i, ''))}</button>`;
}
/* Rulebook ORPHANS (Jac 2026-06-13): live-DOM elements the lint flags — a control
   class with NO data-r, i.e. no rule yet. Live (not source) because rule attrs are
   interpolated, so a static scan can't tell ruled from un-ruled. De-duped by label;
   excludes the rulebook overlay itself. Lists what's in the CURRENT view. */
function unruledElements() {
  const sel = '.pill:not([data-r]), .add-field:not([data-r]), .flag:not([data-r]), .linkname:not([data-r]), .inv-line-link:not([data-r]), .req:not([data-r]), .file-drop:not([data-r]), .datefield:not([data-r]), .seg:not([data-r])';
  const seen = new Set(), out = [];
  Array.from(document.querySelectorAll(sel)).forEach((e) => {
    if (e.closest('.overlay')) return;
    const cls = String(e.className || '').split(' ')[0] || e.tagName.toLowerCase();
    let txt = (e.textContent || '').trim().replace(/\s+/g, ' '); txt = txt.length > 36 ? txt.slice(0, 36) + '…' : (txt || '·');
    const key = cls + '|' + txt; if (seen.has(key)) return; seen.add(key);
    out.push({ cls, txt });
  });
  return out;
}
/** R22: the deliberate close/remove ✕ — a red circle, white ✕. `hover:true` reveals
 *  it only on the container's hover (tabs/rows); otherwise always on. Reusable. */
function closeX(js, { data, hover } = {}) {
  return `<button class="close-x${hover ? ' hoveronly' : ''}${js ? ' ' + js : ''}" data-r="R24"${dataAttrs(data)} data-tip="Close">${I.x}</button>`;
}
/** R26: MANUAL LINK — icon-only ghost circle, opens a service task's cited OEM
 *  manual page in a new tab (Jac 2026-07-07: every model task now carries a
 *  sourceUrl alongside its `source` citation). Renders NOTHING when the caller
 *  has no real sourceUrl — an honest miss, never a dead/fake link (same spirit
 *  as categoryIconFor's neutral box glyph). `cite` (the task's rich `source`
 *  text) rides as the tooltip when short enough to read at a glance. */
function sourceLinkBtn(url, cite) {
  if (!url) return '';
  const tip = (cite && cite.length <= 140) ? cite : 'View in manual';
  return `<a class="icon-link" data-r="R26" href="${esc(url)}" target="_blank" rel="noopener" data-tip="${esc(tip)}">${I.linkOut}</a>`;
}
/* SERVICE DETAIL PANEL (Jac 2026-07-08 — "REALLY hold their hands"): a service task's
 * optional `detail` object (fluidType/fluidCapacity/partRefs/notes) drives the "What
 * you need" block in the service-completion popup. Parts are editable IN PLACE — they
 * reuse the exact WO Work-Order line idiom (.woline row + closeX remove + the partform
 * popup for add/edit) rather than inventing a parallel parts UI, per Jac's "this should
 * nearly already exist because of Work Orders" note. Edits write to the REAL model task
 * (unitServiceRows returns a merged/derived copy), never the copy — see
 * removeSvcPartRef / savePartForm's taskTarget branch. */
function svcRealTask(u, task) {
  const mo = u && u.modelId ? IDX.model.get(u.modelId) : null;
  return mo ? { mo, realTask: (mo.tasks || []).find((t) => t.taskId === task.taskId) || null } : { mo: null, realTask: null };
}
function svcNeedHtml(u, task) {
  const { realTask } = svcRealTask(u, task);
  const editable = !!realTask;
  const d = task.detail || null;
  if (!d) {
    return (task.parts && task.parts.length)
      ? `Parts: ${esc(task.parts.join(' · '))}`
      : '<span class="muted">No detailed spec on file for this task yet.</span>';
  }
  const partRefs = d.partRefs || [];
  const fluidHtml = (d.fluidType || d.fluidCapacity) ? `<div class="svc-fluid">${I.droplet}<span class="svc-fluid-txt">${d.fluidCapacity ? `<b>${esc(d.fluidCapacity)}</b>` : ''}${d.fluidCapacity && d.fluidType ? ' · ' : ''}${d.fluidType ? esc(d.fluidType) : ''}</span></div>` : '';
  const notesHtml = d.notes ? `<div class="muted svc-notes">${esc(d.notes)}</div>` : '';
  const rows = partRefs.map((pr, idx) => `
    <div class="woline">
      <span class="js-svc-part" data-idx="${idx}" style="cursor:pointer">${esc(pr.name || 'Part')}</span>
      <span class="nums">${pr.cost != null ? `<b>${money(pr.cost)}</b>` : ''}<span>${esc(pr.oem || '—')}</span></span>
      <span class="woline-acts">${editable ? closeX('js-svc-part-remove', { data: { unit: u.unitId, task: task.taskId, idx } }) : ''}</span>
    </div>`).join('');
  const partsBlock = (partRefs.length || editable) ? `
    <div class="svc-parts-head">Parts / filters${editable ? '<span class="svc-editnote"> · edits this model’s schedule</span>' : ''}</div>
    ${rows}
    ${editable ? `<div class="svc-partadd">${addBtn('Part', { line: true, js: 'js-svc-addpart', h: 26, data: { unit: u.unitId, task: task.taskId } })}${actionPill('commit', 'Browse catalog', { js: 'js-svc-browseparts', data: { unit: u.unitId, task: task.taskId }, h: 26 })}</div>` : ''}` : '';
  return `${fluidHtml}${notesHtml}${partsBlock}` || '<span class="muted">No detailed spec on file for this task yet.</span>';
}
/** The part-detail side panel — a SECOND .popup appended to the same overlay (the
 * cardSub / newCustomer §14 side-by-side precedent), showing a clicked partRef's
 * vendor/cost. Prefers values the mechanic already entered directly on the partRef
 * (via partform); falls back to a DATA.parts catalog match by OEM/productNumber;
 * an honest "not in catalog yet" when neither is on file. */
function svcPartPanelEl(u, task, pr, idx) {
  const norm = (s) => String(s || '').trim().toLowerCase();
  const catalogPart = pr.oem ? DATA.parts.find((p) => p.productNumber && norm(p.productNumber) === norm(pr.oem)) : null;
  const vendor = (pr.vendorId && (IDX.vendor.get(pr.vendorId) || DATA.vendors.find((v) => v.vendorId === pr.vendorId)))
    || (catalogPart && catalogPart.vendorId && (IDX.vendor.get(catalogPart.vendorId) || DATA.vendors.find((v) => v.vendorId === catalogPart.vendorId))) || null;
  const cost = pr.cost != null ? pr.cost : (catalogPart ? catalogPart.priceEach : null);
  const url = pr.url || (catalogPart ? catalogPart.website : '');
  const img = pr.photo || (catalogPart ? catalogPart.imageUrl : '');
  const enriched = !!(vendor || cost != null || url || catalogPart);
  const webUrl = (w) => (/^https?:\/\//i.test(w) ? w : 'https://' + w);
  const vendorBlock = vendor ? `
      <div class="svc-ref-head" style="margin-top:14px">Vendor</div>
      <div class="svc-vendor-block">
        <div class="svc-vendor-name">${esc(vendor.name || '')}</div>
        ${vendor.primaryContact ? `<div class="muted" style="font-size:11.5px">${esc(vendor.primaryContact)}</div>` : ''}
        ${vendor.phone ? linkName(vendor.phone, { js: 'js-open-link', data: { url: 'tel:' + String(vendor.phone).replace(/[^\d+]/g, '') } }) : ''}
        ${vendor.email ? linkName(vendor.email, { js: 'js-open-link', data: { url: 'mailto:' + vendor.email } }) : ''}
        ${vendor.website ? linkName(vendor.website, { js: 'js-open-link', data: { url: webUrl(vendor.website) } }) : ''}
      </div>` : (enriched ? '' : `
      <p class="muted" style="font-size:12px;margin-top:8px">Not in the parts catalog yet.</p>
      <div class="svc-part-row">${linkName('Search this part number ↗', { js: 'js-open-link', data: { url: 'https://www.google.com/search?q=' + encodeURIComponent(pr.oem || pr.name || '') } })}</div>`);
  const pp = el('div', 'popup svc-part-popup'); pp.style.width = '300px';
  pp.innerHTML = popupShell({
    icon: CARD_ICON.parts || '', title: pr.name || 'Part',
    tag: catalogPart ? 'Parts catalog · match' : (enriched ? 'Service · part' : 'Parts catalog · not on file'),
    closeJs: 'js-svc-part-close',
    body: `
      ${img ? `<img class="insp-thumb" src="${esc(img)}" alt="${esc(pr.name || 'part')}">` : ''}
      <div class="muted" style="font-size:11px;margin-bottom:8px">OEM ${esc(pr.oem || '—')}${catalogPart ? ` · Catalog ${esc(catalogPart.productNumber || '')}` : ''}</div>
      ${cost != null ? kv(money(cost), { pfx: 'Cost', derived: pr.cost == null }) : ''}
      ${catalogPart && catalogPart.qtyOnHand != null ? kv(catalogPart.qtyOnHand + ' on hand', { pfx: 'Stock', derived: true }) : ''}
      ${url ? `<div class="svc-part-row">${linkName(url.length > 30 ? 'Order / info ↗' : url, { js: 'js-open-link', data: { url: webUrl(url) } })}</div>` : ''}
      ${vendorBlock}`,
    foot: `${ghostPill('Close', { js: 'js-svc-part-close' })}${actionPill('commit', 'Edit', { js: 'js-svc-partedit', data: { unit: u.unitId, task: task.taskId, idx } })}`,
  });
  return pp;
}
function removeSvcPartRef(unitId, taskId, idx) {
  const u = IDX.unit.get(unitId); if (!u) return;
  const { mo, realTask } = svcRealTask(u, { taskId });
  if (!realTask || !realTask.detail || !Array.isArray(realTask.detail.partRefs) || !realTask.detail.partRefs[idx]) return;
  const [gone] = realTask.detail.partRefs.splice(idx, 1);
  reindex('models', mo); logAction(mo, `Removed part ${auditVal(gone.name)} from ${realTask.name}`);
  const o = state.overlay;
  if (o && o.kind === 'service' && o.partRef && o.partRef.idx === idx) o.partRef = null;
  else if (o && o.kind === 'service' && o.partRef && o.partRef.idx > idx) o.partRef.idx -= 1;   // keep pointing at the same part after the array shifts
  toast('Part removed.'); renderOverlay();
}
/** Attach an EXISTING catalog part (DATA.parts) onto a service task's detail.partRefs —
 * the "selection" half of the parts UX (Jac 2026-07-08), paired with the partform
 * "create" half. Opened from the parts board in pick mode (js-svc-pick-part). Writes to
 * the REAL model task (svcRealTask + reindex('models',…)), the same idiom as
 * removeSvcPartRef / savePartForm's taskTarget branch — never the unitServiceRows copy.
 * Only carries fields the catalog actually has (undefined, not '', so svcPartPanelEl's
 * "not in catalog yet" fallback still behaves). Dedupes by OEM (when present) or name. */
function attachCatalogPart(unitId, taskId, partId) {
  const u = IDX.unit.get(unitId); if (!u) return;
  const p = DATA.parts.find((x) => x.partId === partId); if (!p) return;
  const { mo, realTask } = svcRealTask(u, { taskId });
  if (!realTask) { toast('No editable schedule for this unit.'); return; }
  realTask.detail = realTask.detail || {};
  realTask.detail.partRefs = realTask.detail.partRefs || [];
  const norm = (s) => String(s || '').trim().toLowerCase();
  const oem = p.productNumber || '';
  const dupe = realTask.detail.partRefs.some((pr) => (oem && pr.oem && norm(pr.oem) === norm(oem)) || (norm(pr.name) && norm(pr.name) === norm(p.name)));
  if (dupe) { toast('Already on this service'); return; }
  const rec = { name: p.name };
  if (oem) rec.oem = oem;
  if (p.priceEach != null) rec.cost = p.priceEach;
  if (p.vendorId) rec.vendorId = p.vendorId;
  if (p.website) rec.url = p.website;
  if (p.imageUrl) rec.photo = p.imageUrl;
  realTask.detail.partRefs.push(rec);
  reindex('models', mo); logAction(mo, `Attached catalog part ${auditVal(p.name)} to ${realTask.name}`);
  toast('Part attached.');
  state.overlay = { kind: 'service', unitId, taskId };
  renderOverlay();
}
/** R6: required-until-entered — white bg + dark ink, stays loud until satisfied. */
function reqBtn(label, { js, data, icon } = {}) {
  return `<button class="req${js ? ' ' + js : ''}" data-r="R6"${dataAttrs(data)}>${icon || ''}${esc(label)}</button>`;
}
/** R7: a hyperlink — blue, italic, permanent underline; navigates when card/rec given.
 *  href → a REAL <a> (tel:, external maps…); ext adds target=_blank rel=noopener;
 *  icon rides left of the label (dimmed to text weight by the .linkname svg rule). */
function linkName(label, { card, recId, js, data, href, ext, icon } = {}) {
  const nav = card ? ` data-pill-card="${card}" data-pill-rec="${esc(recId)}"` : '';
  const body = `${icon || ''}${esc(label)}`;
  if (href) return `<a class="linkname${js ? ' ' + js : ''}" data-r="R7" href="${esc(href)}"${ext ? ' target="_blank" rel="noopener"' : ''}${dataAttrs(data)}>${body}</a>`;
  return `<span class="linkname${js ? ' ' + js : ''}" data-r="R7"${nav}${dataAttrs(data)}>${body}</span>`;
}
/** R9: a title mini-flag + the ≤2-row stack that matches the 30px title chip. */
function flagEl(label, color, { icon, card, recId, title, alert, sect } = {}) {
  // alert: big-deal flags pulse (No Card, active rental, bad pay status — Jac 2026-06-12)
  // sect: clicking also SCROLLS to that section (class) — same card or after nav
  const nav = card ? ` data-pill-card="${card}" data-pill-rec="${esc(recId)}"` : '';
  return `<span class="flag c-${color}${alert ? ' alert' : ''}" data-r="${alert ? 'R9b' : 'R9'}"${nav}${sect ? ` data-sect="${sect}"` : ''}${title ? ` data-tip="${esc(title)}"` : ''}>${icon || ''}${esc(label)}</span>`;
}
const flagsStack = (flags, h) => `<span class="flags" data-r="R9"${h ? ` style="height:${h}px"` : ''}>${flags.filter(Boolean).join('')}</span>`;
/** R21: FILE DROP — the massive add-file zone in popups (Jac 2026-06-12):
    R5b's blue dashed language at full size, ONE rule for every popup "add a file". */
function fileDrop(label, { js, accept = 'image/*', capture, done, icon } = {}) {
  return `<label class="file-drop${done ? ' done' : ''}" data-r="R21">${icon || I.video}<span>${esc(label)}</span><input type="file" accept="${accept}"${capture ? ` capture="${capture}"` : ''} class="${js}" style="display:none"></label>`;
}
/** R22: the ONE date (+optional time) picker — same app-styled calendar everywhere
    a single date/datetime is entered. (The rental WINDOW uses the timeline winpicker,
    not this.) `field` = the state.overlay key it reads/writes; clicking toggles the
    inline calendar below it via datePickerInline(). */
function dateField(field, value, { withTime, time, ph = 'Pick a date' } = {}) {
  const open = state.datepick?.field === field;
  const lbl = value ? (withTime ? `${fmtShortDate(value)}${time ? ' · ' + to12(time) : ''}` : fmtShortDate(value)) : ph;
  return `<button class="datefield js-datepick${value ? '' : ' empty'}${open ? ' on' : ''}" data-r="R22" data-field="${esc(field)}" data-withtime="${withTime ? 1 : ''}">${CARD_ICON.rentals}<span>${esc(lbl)}</span></button>`
    + (open ? datePickerInline() : '');
}
/** R14: a 3-state segmented toggle. opts: [{label, js, data, on:'green'|'yellow'|...}] */
function segCtl(buttons, cls) {
  return `<span class="seg${cls ? ' ' + cls : ''}" data-r="R14">${buttons.map((b) => `<button class="${b.js || ''}${b.on ? ` on-${b.on}` : ''}"${dataAttrs(b.data)}>${b.label}</button>`).join('')}</span>`;
}
/** R19: the ATTENTION FLASH — a glow that points AT what the user must do,
 *  replacing error messages wherever possible (Jac 2026-06-11). */
function attnFlash(sel) {
  document.querySelectorAll(sel).forEach((n) => { n.classList.remove('attn'); void n.offsetWidth; n.classList.add('attn'); setTimeout(() => n.classList.remove('attn'), 2000); });
}
/** R19 fallback: glow the fix when it's ON SCREEN; only use words when it isn't. */
function flashOr(sel, msg) {
  if (document.querySelector(sel)) return attnFlash(sel);
  toast(msg);
}
/** R20: the Wrangler CONTEXT MENU — right-click any element.
 *  Copy/Paste act on the field · Global Search uses the text ·
 *  Add Comment logs to History · Ask Mr. Wrangler copies a debug reference for Claude. */
let ctxTarget = null;
let ctxRecord = null;   // §17b — the record the menu opened on ({card, recId}), for the "+ Target" link actions
// §13.4 graph-chrome right-click menu — tracks which card it was opened on so runCtxAction can act without
// the ctxOutside closer; the chosen state persists per device, per card (loadGvChrome).
let ctxGvCard = null;
function openGvChromeMenu(e, card) {
  closeCtxMenu();
  ctxTarget = null; ctxGvCard = card;
  const ch = loadGvChrome(card);
  const m = document.createElement('div');
  m.className = 'ctx-menu'; m.id = 'rw-ctx';
  const item = (act, label) => `<button class="dd-item" data-ctx="${act}">${label}</button>`;
  m.innerHTML = [
    item('gv-pills', `🏷️ ${ch.pills ? 'Show' : 'Hide'} filter pills`),
    item('gv-sort', `↕️ ${ch.sort ? 'Show' : 'Hide'} Views &amp; sort`),
    '<div class="menu-sep"></div>',
    item('gv-reset', '↺ Reset pills &amp; sort'),
  ].join('');
  document.body.appendChild(m);
  m.style.left = Math.min(e.clientX, window.innerWidth - 205) + 'px';
  m.style.top = Math.min(e.clientY, window.innerHeight - m.offsetHeight - 8) + 'px';
  setTimeout(() => document.addEventListener('mousedown', ctxOutside), 0);
}
function closeCtxMenu() { const m = document.getElementById('rw-ctx'); if (m) m.remove(); }
function openCtxMenu(e, hit) {
  closeCtxMenu();
  ctxTarget = hit;
  // §17b — resolve the pressed record → its menu-driven LINK actions ("+ Target").
  const rr = hit && hit.el ? cardRecordAt(hit.el) : null;
  const ent = rr ? entityCardOf(rr.card, rr.recType) : null;
  ctxRecord = ent ? { card: ent, recId: rr.recId } : null;
  const linkItems = ctxRecord ? linkActionsFor(ctxRecord.card, recOf(ctxRecord.card, ctxRecord.recId)) : [];
  const m = document.createElement('div');
  m.className = 'ctx-menu'; m.id = 'rw-ctx';
  const item = (act, label) => `<button class="dd-item" data-ctx="${act}">${label}</button>`;
  // Invoice-sheet section — right-click the interactive .pr-doc (openCtxMenuAt passes hit.inv):
  // the doc's own actions ride OUR standard menu (Jac 2026-07-17). Email is dropped when there's
  // no address on file (dead action), matching the detail-view Send-Email gate.
  const invRec = hit && hit.inv ? IDX.invoice.get(hit.inv) : null;
  const invCust = invRec && invRec.customerId ? IDX.customer.get(invRec.customerId) : null;
  const invSec = invRec ? [
    item('invPrint', '🖨 Save as PDF / Print'),
    invCust && invCust.email ? item('invEmail', '✉️ Email invoice') : '',
    item('invCopyImg', '🖼 Copy as image'),
    '<div class="menu-sep"></div>',
  ].join('') : '';
  const linkSec = linkItems.length ? linkItems.map((a) => `<button class="dd-item" data-ctx="link:${a.target}">${CARD_ICON[a.target] || ''}${esc(a.label)}</button>`).join('') + '<div class="menu-sep"></div>' : '';
  // D8 comms block — on a customer, Text… / Email… start (or resurrect) that
  // conversation onto the rail. ('Ask Mr. Wrangler about…' rides D8 Phase B.)
  const ctxCust = ctxRecord && ctxRecord.card === 'customers' ? recOf('customers', ctxRecord.recId) : null;
  const commsSec = ctxCust ? `<button class="dd-item" data-ctx="commsText">${I.messageSquare}Text ${esc((ctxCust.firstName || fullName(ctxCust) || 'customer').trim().split(/\s+/)[0])}…</button><button class="dd-item" data-ctx="commsEmail">${I.mail}Email ${esc((ctxCust.firstName || fullName(ctxCust) || 'customer').trim().split(/\s+/)[0])}…</button><div class="menu-sep"></div>` : '';
  m.innerHTML = invSec + commsSec + linkSec + [
    item('copy', '📋 Copy'), item('paste', '📥 Paste'),
    '<div class="menu-sep"></div>',
    item('gsearch', '🌐 Global Search'),
    '<div class="menu-sep"></div>',
    item('comment', '💬 Add Comment'), item('wrangler', '🤠 Ask Mr. Wrangler'),
  ].join('');
  document.body.appendChild(m);
  m.style.left = Math.min(e.clientX, window.innerWidth - 205) + 'px';
  m.style.top = Math.min(e.clientY, window.innerHeight - m.offsetHeight - 8) + 'px';
  setTimeout(() => document.addEventListener('mousedown', ctxOutside), 0);
}
// §M3 — open the right-click/long-press menu for the element at (x,y). Shared by the
// contextmenu handler (mouse) and the touch long-press timer (phone). Mirrors the §R20
// logic: a real "leaf" tool opens the Wrangler menu; card dead-space → card-to-List.
let lastTouchCtx = 0;
let lastCtx = { t: 0, card: null };   // §R20 single vs double right-click tracker — MODULE-level so openCtxMenuAt (below) can read it
function openCtxMenuAt(target, x, y) {
  if (!target || !target.closest) return;
  if (target.closest('input, textarea, .inline-input')) return;
  const card = target.closest('.card'); if (!card && !target.closest('.overlay .popup')) return;
  // §2.3 Phase 3 — right-click / long-press on a Trips row body opens the trip's own
  // Merge/Split menu (openTripMenu), not the generic Wrangler record menu below: a
  // derived/materialized Trip isn't a real card record. Excludes linked-record pills,
  // real links, and the per-leg controls so THEIR own right-click behavior (e.g. a
  // rental pill's "+Target" link actions) still works exactly as it did before —
  // this only claims the row's own dead space (badge/time/town/spacer/Done/⋯), the
  // SAME area whose left-click already toggles the cab sheet.
  const tripRow = target.closest('.row[data-card="calendar"]');
  if (tripRow && !target.closest('[data-pill-card], a[href], .dt-time, .js-stop-driver, .js-trip-driver')) {
    openTripMenu(tripRow.dataset.rec, tripRow.dataset.day, tripRow);
    return;
  }
  // §13.4 — inside an OPEN graph view, right-click/long-press the panel (or the Views & sort
  // control above it) opens the graph-chrome menu instead of the per-element Wrangler menu,
  // so the filter pills / sort can be hidden and Reset.
  if (card && !(state.winEdit && state.winEdit.anchor)) {
    const cid = card.dataset.card, gcs = cid && activeSession().cards[cid];
    if (gcs && gcs.graphView && (target.closest('.gv-panel') || target.closest('.sort'))) return openGvChromeMenu({ clientX: x, clientY: y }, cid);
  }
  // While the rental-window picker is open, keep right-click → BACK working; just suppress
  // the element context menu (it gets in the way of picking). (Jac B5, 2026-06-15)
  const leaf = (state.winEdit && state.winEdit.anchor) ? null : target.closest('.pill, .add-field, .flag, .linkname, .inv-line-link, .req, .seg, button, .inline-edit, .jnode, .x, a, .d-title, .r-title, .derived');
  const hit = leaf ? (ruleOf(leaf) || { r: null, el: leaf }) : null;
  if (hit) return openCtxMenu({ clientX: x, clientY: y }, hit);
  if (!card) return;
  // Right-click / long-press ON the interactive invoice sheet opens OUR standard menu with an
  // invoice section (Print/Save-PDF · Email · Copy image) — NOT the "right-click = Back" collapse
  // that made the doc unusable and swallowed the native menu (Jac 2026-07-17). A genuine leaf inside
  // the doc (the PO inline-edit, a source-link ↗) already returned above, so it keeps its own menu.
  // The print copy in #print-root carries no data-inv, so it's untouched.
  const invDoc = target.closest('.pr-doc[data-inv]');
  if (invDoc) return openCtxMenu({ clientX: x, clientY: y }, { r: null, el: target, inv: invDoc.dataset.inv });
  // §17b PHONE: a long-press on EMPTY space (row gaps, an open standard card) still opens
  // the menu on the record there, so linking works from ANYWHERE on a row/card — not just
  // a leaf. The right-click "go Back / clear anchor" on empty space stays a DESKTOP-only
  // convention; a phone long-press must never silently navigate Back. (Jac, 2026-06-30)
  if (document.body.classList.contains('is-phone')) {
    if (cardRecordAt(target)) return openCtxMenu({ clientX: x, clientY: y }, { r: null, el: target });
    return;   // truly empty list space → do nothing (never Back on a phone long-press)
  }
  const dc = card.dataset.card, now = performance.now();
  if (now - lastCtx.t < 450 && lastCtx.card === dc) { lastCtx = { t: 0, card: null }; return clearAnchor(); }   // double right-click
  lastCtx = { t: now, card: dc };
  cardBack(dc);
}
function ctxOutside(e) {
  if (e.target.closest && e.target.closest('#rw-ctx')) return;
  document.removeEventListener('mousedown', ctxOutside);
  closeCtxMenu();
}
function runCtxAction(act) {
  if (act.startsWith('gv-')) {   // §13.4 graph-chrome menu — no leaf target, just the card
    const card = ctxGvCard; closeCtxMenu(); document.removeEventListener('mousedown', ctxOutside); ctxGvCard = null;
    if (!card) return;
    if (act === 'gv-pills') saveGvChrome(card, { pills: !gvPillsHidden(card) });
    else if (act === 'gv-sort') saveGvChrome(card, { sort: !gvSortHidden(card) });
    else if (act === 'gv-reset') saveGvChrome(card, { pills: false, sort: false });
    return render();
  }
  if (act === 'commsText' || act === 'commsEmail') {   // D8 — start/resume a customer conversation from the R20 menu
    const rec = ctxRecord; closeCtxMenu(); document.removeEventListener('mousedown', ctxOutside); ctxRecord = null;
    if (rec && rec.card === 'customers') commsOpenConv(act === 'commsText' ? 'text' : 'email', rec.recId);
    return;
  }
  if (act.startsWith('link:')) {   // §17b — menu-driven linking
    const target = act.slice(5); const rec = ctxRecord;
    closeCtxMenu(); document.removeEventListener('mousedown', ctxOutside); ctxRecord = null;
    if (!rec) return;
    if (rec.card === 'units' && target === 'workOrders') return startUnitWorkOrder(rec.recId);   // §4a create-WO → land on the unit
    return enterLinking(rec.card, rec.recId, target);
  }
  const tg = ctxTarget; closeCtxMenu(); document.removeEventListener('mousedown', ctxOutside);
  if (!tg) return;
  const el = tg.el;
  if (act === 'invPrint') return printInvoice(tg.inv);                 // 🖨 → the yard-log print/Save-as-PDF dialog
  if (act === 'invEmail') return sendInvoiceEmail(tg.inv, el);         // ✉️ → existing invoice-email path (server send, or mailto in demo)
  if (act === 'invCopyImg') return copyInvoiceImage(tg.inv);           // 🖼 → rasterize the sheet to the clipboard as a PNG
  const text = (el.textContent || '').replace(/\s+/g, ' ').trim();
  const editSpan = el.classList?.contains('inline-edit') ? el : (el.closest('.inline-edit') || el.querySelector?.('.inline-edit'));
  const setField = (v) => {
    if (!editSpan) return attnFlash('.inline-edit');
    // route through startInlineEdit's commit so every data-edit kind keeps its own casts/side-effects/audit log
    startInlineEdit(editSpan);
    const input = document.activeElement;
    if (!input || !input.classList || !input.classList.contains('inline-input')) return attnFlash('.inline-edit');
    input.value = v == null ? '' : String(v);
    input.blur();
  };
  if (act === 'copy') { try { navigator.clipboard.writeText(text); } catch (err) {} return toast('📋 Copied.'); }
  if (act === 'paste') { navigator.clipboard.readText().then((v) => setField(v)).catch(() => toast('Clipboard unavailable — paste into the field directly.')); return; }
  if (act === 'gsearch') return setQuery(text);
  if (act === 'comment') {
    // Phase 6 — open the colored-comment composer for the right-clicked record.
    const hit = cardRecordAt(el);
    if (!hit) { toast('Right-click a record (or open one) to comment.'); return; }
    return openOverlay({ kind: 'comment', card: hit.card, recId: hit.recId, recType: hit.recType, color: 'yellow' });
  }
  if (act === 'wrangler') {
    const hit = cardRecordAt(el);   // §18 — open Mr. Wrangler dock, record-aware when a record is under the cursor
    return openWranglerDock({ messages: [], draft: '', attach: [], card: hit ? hit.card : null, recId: hit ? hit.recId : null, recType: hit ? hit.recType : null, reqNumber: null, reqTitle: null, reqUrl: null });
  }
}
/** R17: forward-action pills — commit (blue) / money (green) / danger (solid red). */
function actionPill(kind, label, { js, data, h } = {}) {
  return `<button class="pill c-${kind}${js ? ' ' + js : ''}" data-r="R17"${dataAttrs(data)}${h ? ` style="height:${h}px;font-size:11px"` : ''}>${esc(label)}</button>`;
}
/** R18: the ONE quiet/neutral action — Cancel, Close, secondary tools.
 *  `disabled` greys it (is-disabled) and drops the js hook so it's inert; pair with `tip`
 *  (R23 data-tip) to explain why (e.g. "No email on file"). `icon` renders an icon-only
 *  circular chip (same ghost weight, sized to match a badge) instead of the text label —
 *  the label still becomes the a11y name + the R23 tooltip (e.g. a row's Duplicate action). */
function ghostPill(label, { js, data, tip, disabled, icon } = {}) {
  const tipAttr = icon ? (tip || label) : tip;
  return `<button class="pill ghost${icon ? ' icon-only' : ''}${disabled ? ' is-disabled' : ''}${js && !disabled ? ' ' + js : ''}" data-r="R18"${dataAttrs(data)}${tipAttr ? ` data-tip="${esc(tipAttr)}"` : ''}${icon ? ` aria-label="${esc(label)}"` : ''}${disabled ? ' aria-disabled="true"' : ''}>${icon || esc(label)}</button>`;
}
/** R31: a single interactive TOGGLE CHIP — ONE pill that flips an account-level on/off
 *  flag (PO required, Rental Protection). Distinct from R14 (a GROUP of mutually-exclusive
 *  options riding one joined control): this is a lone control whose own fill communicates
 *  its state — off = quiet outline, on = the registry `tone` color fill. (2026-07-10
 *  Account/Agreements redesign, D22-D24.) */
function toggleChip(label, on, { js, data, tone = 'accent' } = {}) {
  return `<button class="chip-toggle${on ? ` on tone-${tone}` : ''}${js ? ' ' + js : ''}" data-r="R31"${dataAttrs(data)} aria-pressed="${on ? 'true' : 'false'}">${esc(label)}</button>`;
}
/** R33: the GLOBAL-MODE globe — an icon-only toggle pinned to the right of a grid card's
 *  search bar (card-search global mode, 2026-07-13). Flips that bar — and every grid-card
 *  bar in lockstep — between per-card search and whole-yard "global" search: dim steel off,
 *  safety-orange on. A scope-MODE toggle (like R31 but icon-only + it drives the shared
 *  state.query), never a status color. Rendered only when flagOn('cardGlobalSearch'). */
function globeToggle(card, on) {
  const lbl = on ? 'Search this card only' : 'Round up the whole yard — search all cards';
  return `<button class="mini-globe${on ? ' on' : ''} js-cardglobe" data-r="R33" data-card="${esc(card)}" aria-pressed="${on ? 'true' : 'false'}" aria-label="${esc(lbl)}" data-tip="${on ? 'Search this card only' : 'Round up the whole yard'}">${I.globe}</button>`;
}
/** The popup PLATE — every overlay's shell, so they all read as one bolted data-plate.
 *  Hazard cap (red `danger` variant for abort/destroy) + corner rivets + stamped Saira
 *  head (ignition icon · uppercase title · micro tag) + scrollable body + optional sticky
 *  foot. Pure chrome, composed from already-stamped parts (the muted close, R17/R18 in
 *  the foot) — no own data-r. `icon` = an `I.*`/`CARD_ICON.*` glyph; `headRight` =
 *  extra head buttons (e.g. the phone-QR); `body`/`foot` = innerHTML strings. */
function popupShell({ icon, title, tag, danger, headRight = '', headRail = '', body = '', foot = '', closeJs = 'js-close', bodyClass = '' } = {}) {
  // headRail (optional): raw HTML that REPLACES the stamped title block — used when a
  // tab rail IS the header (the card-bound agreements form). Default keeps the title.
  return `
    <div class="pl-cap${danger ? ' danger' : ''}"></div>
    <span class="pl-rivet tl"></span><span class="pl-rivet tr"></span><span class="pl-rivet bl"></span><span class="pl-rivet br"></span>
    <div class="popup-head${headRail ? ' has-rail' : ''}">
      ${headRail || `${icon ? `<span class="pl-ic">${icon}</span>` : ''}<div class="pl-title"><h3>${esc(title || '')}</h3>${tag ? `<span class="pl-tag">${esc(tag)}</span>` : ''}</div><span class="spacer"></span>${headRight}`}
      <button class="x ${closeJs}" aria-label="Close">${I.x}</button>
    </div>
    <div class="popup-body${bodyClass ? ' ' + bodyClass : ''}">${body}</div>
    ${foot ? `<div class="popup-foot">${foot}</div>` : ''}`;
}

