  if (f.length === 1) return flagsStack([flagEl(top.label, top.color, { alert: top.alert, title: top.label })]);
  return flagsStack([flagEl(`${top.label} +${f.length - 1}`, top.color, { alert: top.alert, title: f.map((x) => x.label).join(' · ') })]);
