const KPI_TOKENS = { '@thisMonth': () => TODAY_ISO.slice(0, 7), '@today': () => TODAY_ISO };
const kpiField = (rec, f) => (f && f[0] === '_' && KPI_DERIVED[f]) ? KPI_DERIVED[f](rec) : rec[f];
const kpiVal = (v) => (typeof v === 'string' && KPI_TOKENS[v]) ? KPI_TOKENS[v]() : v;
