  const rows = Object.entries(by).sort((a, b) => b[1] - a[1]).slice(0, 8).map(([n, bal]) => ({ name: n, disp: money(bal), card: 'invoices', col: 'customer', navValue: n, tip: `${n} — ${money(bal)} open` }));
