  const n = bk.length, pts = bk.map((b, i) => ({ i, label: b.label, v: vals[i] }));
  const show = new Set(n <= 6 ? pts.map((p) => p.i) : [0, 1, 2, 3, 4].map((k) => Math.round(k * (n - 1) / 4)));
