  const parts = [created ? `added ${created}` : '', updated ? `updated ${updated}` : ''].filter(Boolean);
  if (parts.length) toast(`Mr. Wrangler ${parts.join(' · ')}. 🤠`);
  else if (!operated) toast('Mr. Wrangler made no changes. 🤠');
