// Wire the signature canvas for finger/stylus/mouse/pen drawing (white bg → JPEG export).
function setupSignaturePad() {
  // Wire EVERY pad in the overlay (the capture can ride the card signing tab and/or
  // the +Card panel) — match each backing store to its rendered size so strokes
  // aren't stretched (the pad is width:auto in the flex row); rects are laid out by now.
  const o = state.overlay;
  document.querySelectorAll('.overlay .nc-sigpad').forEach((cv) => {
    const r = cv.getBoundingClientRect(); if (r.width && r.height) { cv.width = Math.round(r.width); cv.height = Math.round(r.height); }
    const ctx = cv.getContext('2d');
    ctx.fillStyle = '#fff'; ctx.fillRect(0, 0, cv.width, cv.height);
    ctx.strokeStyle = (getComputedStyle(document.documentElement).getPropertyValue('--accent') || '#ff7a1a').trim();   // orange ink (Jac)
    ctx.lineWidth = 2.4; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
    // re-apply a signature already captured (2nd-screen popout, or before this re-render) so taking a selfie etc. can't wipe it
    const _ctx = captureCtx(o); const cur = _ctx.k ? ((cardDraftSig(_ctx.k) || {}).signature || '') : ((_ctx.c && _ctx.c.pendingCapture && _ctx.c.pendingCapture.signature) || '');   // re-apply the card's saved draft signature (re-render / 2nd-screen / re-open)
    if (cur) { const img = new Image(); img.onload = () => { ctx.drawImage(img, 0, 0, cv.width, cv.height); cv.dataset.drawn = '1'; }; img.src = cur; }
    let drawing = false, last = null;
    const pos = (e) => { const b = cv.getBoundingClientRect(); return { x: (e.clientX - b.left) * (cv.width / b.width), y: (e.clientY - b.top) * (cv.height / b.height) }; };
    const stash = () => { if (drawing) { drawing = false; captureSignature(o, cv.toDataURL('image/jpeg', 0.8)); scheduleFinalizeSign(o); } };   // auto-save the draft; finalize once the pen rests
    cv.addEventListener('pointerdown', (e) => { e.preventDefault(); drawing = true; last = pos(e); cv.dataset.drawn = '1'; clearTimeout(_signFinalizeT); cv.setPointerCapture(e.pointerId); });
    cv.addEventListener('pointermove', (e) => { if (!drawing) return; e.preventDefault(); const p = pos(e); ctx.lineWidth = (e.pointerType === 'pen' && e.pressure > 0) ? (1.4 + e.pressure * 2.6) : 2.4; ctx.beginPath(); ctx.moveTo(last.x, last.y); ctx.lineTo(p.x, p.y); ctx.stroke(); last = p; });
    cv.addEventListener('pointerup', stash);
    cv.addEventListener('pointerleave', stash);
  });
}
const closeOverlay = () => { destroyCardElement(); stopAgCam(); try { if (_sigWin && !_sigWin.closed) _sigWin.close(); } catch (e) {} _sigWin = null; clearTimeout(_gpsPollTimer); state.datepick = null; state.overlay = null; renderOverlay(); };

/* ── Back-office boards (§7.9–7.12): spreadsheet-style tables ─────────────── */
function vendorTotals(vendorId) {
  const exp = DATA.expenses.filter((e) => e.vendorId === vendorId);
  const totalSpent = exp.reduce((a, e) => a + (Number(e.amount) || 0), 0);
  const partsCount = DATA.parts.filter((p) => p.vendorId === vendorId).length;
  return { totalSpent, partsCount, avgCost: partsCount ? Math.round(totalSpent / partsCount) : 0 };
}
/* Receipt reconcile math (§7.11 v2, old-app "ONE SOURCE, ONE HOME"): parts link via
   part.receiptId (+receiptQty); Unaccounted = amount − Σ qty×priceEach — green at $0. */
const receiptParts = (expenseId) => DATA.parts.filter((p) => p.receiptId === expenseId);
const receiptLineTotal = (expenseId) => receiptParts(expenseId).reduce((a, p) => a + (Number(p.receiptQty) || 1) * (Number(p.priceEach) || 0), 0);
const reviewState = (iso) => { const d = parseISO(iso); if (!d) return ''; if (d < TODAY) return badge('Overdue', 'red'); return (d - TODAY) / 86400000 <= 30 ? badge('Review soon', 'yellow') : ''; };   // 3-state (audit fix): overdue was invisible under the old d >= TODAY clause
