    <div class="alloc-head"><span>Refund by line item</span>${lines.length > 1 ? `<button class="add-field anchor js-refund-auto" data-r="R5b" type="button" ${o.busy ? 'disabled' : ''}>Refund in full</button>` : ''}</div>
