function destroyCardElement() { if (_cardElement) { try { _cardElement.destroy(); } catch (e) {} } _cardElement = null; _cardElements = null; }

// Reject if a promise hasn't settled in `ms` so a STALLED (never-resolving) backend
// round-trip can't leave the save button spinning "Saving…" forever with no error.
// fetch() has no built-in timeout; a hung Apps Script call otherwise never rejects.
// Server round-trips get 30s; the interactive card confirm gets a GENEROUS 180s bound (#172) so a true
// infinite hang surfaces as an error, without aborting a legitimate (slower) 3DS prompt mid-authentication.
function withTimeout(promise, ms, label) {
  let t; const timeout = new Promise((_, rej) => { t = setTimeout(() => { const e = new Error((label || 'Request') + ' timed out'); e.rwTimeout = true; rej(e); }, ms); });
  return Promise.race([promise, timeout]).finally(() => clearTimeout(t));
}

// Save card: SetupIntent (server) → confirmCardSetup (browser) → persist (server).
// DOM-driven (no renderOverlay) so the Card Element isn't wiped mid-entry.
async function saveCardFlow(btn) {
  const o = state.overlay; const sub = !!(o && o.kind === 'newCustomer' && o.cardSub);   // §14 card panel beside the onboarding form
  if (!o || (o.kind !== 'addCard' && !sub)) return;
  const c = IDX.customer.get(sub ? o.editId : o.customerId); if (!c) return;
  const stripe = getStripe(); if (!stripe || !_cardElement) return;
  const errBox = document.getElementById('sl-card-error');
  const setErr = (m) => { if (errBox) errBox.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Save card'; };
  // Surface failures LOUDLY (a toast), not just in the small card-field box, so a
  // backend/Stripe error can't silently look like "nothing happened".
  const fail = (m) => { setErr(m); toast('Card not saved — ' + (m || 'try again.')); reset(); };
  // §7.1b a card saves UNSIGNED — the signature/selfie are captured per-card AFTER
  // saving (the signing tab), so DON'T gate the save on a customer-level signature.
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  btn.disabled = true; btn.textContent = 'Saving…'; setErr('');
  try {
    const r = await withTimeout(backendCall('stripeSetupIntent', { customerId: c.customerId }), 30000, 'Setting up the card');
    if (!live()) return;
    if (!r || !r.ok) return fail(friendlyPayErr(r));
    // #172 the interactive confirm CAN stall forever (dead network / a 3DS that never resolves), leaving the
    // button spinning "Saving…" with no error. Bound it GENEROUSLY (180s — tolerates a real 3DS prompt) so a
    // true hang surfaces as an error instead of an infinite spinner. The catch below maps rwTimeout → a toast.
    const { setupIntent, error } = await withTimeout(stripe.confirmCardSetup(r.clientSecret, { payment_method: { card: _cardElement, billing_details: { name: c.name || undefined, email: c.email || undefined, phone: c.phone || undefined } } }), 180000, 'Card confirmation');
    if (!live()) return;
    if (error) return fail(error.message);
    if (!setupIntent || setupIntent.status !== 'succeeded') return fail('Card could not be saved — try again.');
    const s = await withTimeout(backendCall('stripeSaveCard', { customerId: c.customerId, paymentMethodId: setupIntent.payment_method, setupIntentId: setupIntent.id }), 30000, 'Saving the card');
    if (!live()) return;
    if (!s || !s.ok) return fail(friendlyPayErr(s));
    c.stripeId = r.stripeId || c.stripeId;
    if (!Array.isArray(c.cards)) c.cards = [];
    const firstCard = customerCards(c).length === 0;
    const newCardId = 'CARD-' + setupIntent.payment_method;   // anchor to the globally-unique Stripe PM id (was 'CARD-'+state.seq, which reset per session and collided across sessions/devices → wrong-card charges / can't-delete / signature bleed)
    // §7.1c a card lands IN PROGRESS — chargeable immediately, but the account can't go On Rent /
    // log deliveries until the card is COMPLETE (card + selfie + signature). Any selfie/signature
    // captured in this panel were held on c.pendingCapture and now saddle onto the new card.
    const newCard = { id: newCardId, stripePmId: setupIntent.payment_method, fingerprint: s.card.fingerprint || '', brand: s.card.brand, last4: s.card.last4,
      expMonth: s.card.expMonth, expYear: s.card.expYear, nickname: o.nickname || '', notes: '', isDefault: firstCard, status: 'active',
      selfie: '', driveSelfieUrl: '', draftSignature: null, agreements: [] };
    // Stripe attaches the SAME physical card as a NEW pm every time it's saved. If this card's
    // fingerprint matches one already on file, SUPERSEDE that entry in place — carry its signed
    // agreement/selfie onto the fresh pm, retire the old pm — so one physical card never piles up
    // as duplicate chips. (Functional now that stripeSaveCard returns card.fingerprint.)
    const _dup = newCard.fingerprint ? customerCards(c).find((k) => k.fingerprint === newCard.fingerprint) : null;
    if (_dup) {
      newCard.agreements = _dup.agreements || []; newCard.selfie = _dup.selfie || ''; newCard.driveSelfieUrl = _dup.driveSelfieUrl || '';
      newCard.isDefault = newCard.isDefault || _dup.isDefault;
      _dup.status = 'removed';
      if (backendPassword && _dup.stripePmId && _dup.stripePmId !== setupIntent.payment_method) backendCall('stripeRemoveCard', { customerId: c.customerId, paymentMethodId: _dup.stripePmId }).catch(() => {});
    }
    c.cards.push(newCard);
    c.cardBrand = s.card.brand; c.cardLast4 = s.card.last4; c.cardExpMonth = s.card.expMonth; c.cardExpYear = s.card.expYear;   // legacy mirror (default card)
    saddlePendingCapture(c, newCard);                                                            // held selfie/signature → this card, then finalize if all three are present
    if (!cardComplete(c, newCard) && c.pendingSigning && c.pendingSigning.signature) attachHeldSigning(c, newCard);   // legacy held packet (pre-#7.1c) back-compat
    const authd = cardComplete(c, newCard);
    reindex('customers', c); logAction(c, `Card added — ${brandName(s.card.brand)} ••••${s.card.last4}${authd ? '' : ' (in progress)'}`);
    destroyCardElement();
    // "authorized" here = the customer authorized FUTURE charges (card-on-file mandate) — NOT a payment.
    // Say so plainly so a saved card is never mistaken for money collected (#false-charge incident).
    toast(authd ? 'Card saved on file — agreement complete ✓ (no charge taken)' : 'Card saved on file — finish selfie + signature to authorize (no charge taken)');
    // Land on the new card's SIGNING tab no matter how Add-card was opened.
    if (sub) { o.cardSub = false; o.tab = newCardId; renderOverlay(); }   // §14 panel beside the form → switch its tab
    else if (o.returnTo === 'payment' && o.invoiceId) openPayInvoice(o.invoiceId);
    else { closeOverlay(); openCustomerForm(c.customerId); if (state.overlay) { state.overlay.tab = newCardId; renderOverlay(); } }   // standalone → open the account form on the signing tab
    render();
  } catch (e) { fail(e && e.rwTimeout ? 'Saving timed out — check your connection and try again.' : 'Network error — try again.'); }
}

// Save ACH: bank SetupIntent (server) → confirmUsBankAccountSetup (browser; raw
// routing/account go straight to Stripe, never to us) → persist (server). Stored
// verified:false until the micro-deposit verification flow ships ("store now, verify
// later", Jac). No Stripe Element — ACH is plain fields handed to Stripe at confirm.
async function saveAchFlow(btn) {
  const o = state.overlay; if (!o || o.kind !== 'addAch') return;
  const c = IDX.customer.get(o.customerId); if (!c) return;
  const stripe = getStripe(); if (!stripe) return;
  const setErr = (m) => { const b = document.getElementById('sl-ach-error'); if (b) b.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Save ACH'; };
  if (!c.signature || !c.selfie) { setErr('Capture a selfie + signature first (ACH authorization).'); return; }
  const holder = (document.getElementById('sl-ach-holder')?.value || '').trim();
  const routing = (document.getElementById('sl-ach-routing')?.value || '').replace(/\D/g, '');
  const account = (document.getElementById('sl-ach-account')?.value || '').replace(/\D/g, '');
  const acctType = document.getElementById('sl-ach-type')?.value || 'checking';
  const holderType = document.getElementById('sl-ach-holdertype')?.value || 'individual';
  if (!holder) return setErr('Enter the account holder name.');
  if (routing.length !== 9) return setErr('Routing number must be 9 digits.');
  if (account.length < 4) return setErr('Enter the account number.');
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  btn.disabled = true; btn.textContent = 'Saving…'; setErr('');
  try {
    const r = await backendCall('stripeBankSetupIntent', { customerId: c.customerId });
    if (!live()) return;
    if (!r || !r.ok) { setErr(friendlyPayErr(r)); reset(); return; }
    const { setupIntent, error } = await stripe.confirmUsBankAccountSetup(r.clientSecret, {
      payment_method: { us_bank_account: { routing_number: routing, account_number: account, account_holder_type: holderType, account_type: acctType }, billing_details: { name: holder, email: c.email || undefined } },
    });
    if (!live()) return;
    if (error) { setErr(error.message); reset(); return; }
    if (!setupIntent || !setupIntent.payment_method) { setErr('Bank account could not be saved — try again.'); reset(); return; }
    const s = await backendCall('stripeSaveBank', { customerId: c.customerId, paymentMethodId: setupIntent.payment_method, setupIntentId: setupIntent.id });
    if (!live()) return;
    if (!s || !s.ok) { setErr(friendlyPayErr(s)); reset(); return; }
    c.stripeId = r.stripeId || c.stripeId;
    if (!Array.isArray(c.achAccounts)) c.achAccounts = [];
    const firstBank = customerBanks(c).length === 0;
    const verified = setupIntent.status === 'succeeded';   // microdeposit/instant pending → requires_action → verified:false
    c.achAccounts.push({ id: 'ACH-' + (state.seq++), stripePmId: setupIntent.payment_method, setupIntentId: setupIntent.id, bankName: s.bank.bankName, last4: s.bank.last4,
      accountType: s.bank.accountType || acctType, holder, isDefault: firstBank, verified, status: 'active',
      mandate: { signedAt: TODAY_ISO, version: 'ach', signature: c.signature, selfie: c.selfie } });
    reindex('customers', c); logAction(c, `ACH added — ${s.bank.bankName} ••••${s.bank.last4}${verified ? '' : ' (verification pending)'}`);
    toast(verified ? 'Bank account saved ✓' : 'Bank account saved — verification pending');
    closeOverlay(); render();
  } catch (e) { setErr('Network error — try again.'); reset(); }
}

// §14b verify a pending ACH with the micro-deposit descriptor code (server does the
// Stripe verify_microdeposits call). On success the bank flips to verified → chargeable.
async function verifyAchFlow(btn) {
  const o = state.overlay; if (!o || o.kind !== 'verifyAch') return;
  const c = IDX.customer.get(o.customerId); if (!c) return;
  const k = customerBanks(c).find((x) => x.id === o.bankId); if (!k) return;
  const setErr = (m) => { const b = document.getElementById('sl-vach-error'); if (b) b.textContent = m || ''; };
  const reset = () => { btn.disabled = false; btn.textContent = 'Verify account'; };
  const code = (document.getElementById('sl-vach-code')?.value || '').trim().toUpperCase();
  if (!/^SM[0-9A-Z]{4}$/.test(code)) { setErr('Enter the 6-character code from the statement (starts with SM).'); return; }
  const live = () => state.overlay === o;
  btn.disabled = true; btn.textContent = 'Verifying…'; setErr('');
  try {
    const r = await backendCall('stripeVerifyBank', { customerId: c.customerId, setupIntentId: k.setupIntentId, descriptorCode: code });
    if (!live()) return;
    if (!r || !r.ok) { setErr(friendlyPayErr(r)); reset(); return; }
    k.verified = true;
    reindex('customers', c); logAction(c, `ACH verified — ${k.bankName || 'Bank'} ••••${k.last4}`);
    toast('Bank account verified ✓'); closeOverlay(); render();
  } catch (e) { setErr('Network error — try again.'); reset(); }
}

// §14b reconcile a processing ACH — poll the PaymentIntent. The server settles it
// (records the charge) if it succeeded, or clears it if it bounced. Reuses finalize.
async function checkAchStatus(invoiceId, piId) {
  try {
    const f = await backendCall('stripeFinalizeInvoice', { invoiceId, paymentIntentId: piId });
    if (f && f.ok) { applyPayment(invoiceId, f, null); const inv = IDX.invoice.get(invoiceId); if (inv) delete inv.achProcessing; toast('ACH cleared — payment received ✓'); render(); return; }
    if (f && f.error === 'ach-failed') { const inv = IDX.invoice.get(invoiceId); if (inv) { delete inv.achProcessing; delete inv.pendingPaymentIntentId; } toast('ACH was returned — charge another way.'); render(); return; }
    toast('Still processing — ACH usually settles in 3–5 business days.');
  } catch (e) { toast('Couldn’t check status — try again.'); }
}

// Charge an invoice off_session; on 3DS fall back to an on-session confirm, then
// re-verify server-side before marking paid. The payment overlay has no Card
// Element, so re-rendering it for busy/error states is safe.
/* PO gate (customers-crm requiresPO, Jac 2026-07-15): a customer flagged "PO required"
   must carry a PO # on the invoice before ANY money moves on it OR it's sent to them — a
   HARD block ("Block ALL"), beyond the advisory red "PO #" chip + the on-rent warning.
   Guards EVERY payment path (card charge, cash, check — human UI + Mr. Wrangler) and both
   customer-facing sends. cust.requiresPO && !inv.po. */
function invoicePoBlocked(inv) {
  if (!inv) return false;
  const c = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  return !!(c && c.requiresPO && !inv.po);
}
async function chargeInvoiceFlow(invoiceId) {
  if (!canMoney()) { toast('Pay/Charge/Refund is Office/Admin only.'); return; }   // #552 audit item 4: defence-in-depth
  { const inv = IDX.invoice.get(invoiceId); if (invoicePoBlocked(inv)) { toast('PO required for this customer — add the PO # before charging a card.'); return; } }   // PO gate — hard-block the card charge until a PO # is on the invoice
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const live = () => state.overlay === o;   // bail if the overlay changed/closed mid-await
  // §19: when the allocation rows are present, the gross + per-line split come
  // from o.alloc (pre-tax inputs). Otherwise fall back to the free amount field.
  let amountCents, alloc = null;
  if (o.alloc) {
    const inv0 = IDX.invoice.get(invoiceId); if (!inv0) return;
    const ch = allocCharge(inv0, o); alloc = ch.alloc;
    if (ch.gross <= 0) { o.error = 'Assign an amount to at least one line.'; return renderOverlay(); }
    amountCents = Math.round(ch.gross * 100);
  } else {
    const amtEl = document.querySelector('.overlay .pay-amt-in');
    const dollars = amtEl ? Number(amtEl.value) : NaN;
    amountCents = dollars > 0 ? Math.round(dollars * 100) : null;   // null = full balance; server caps at balance
  }
  o.busy = true; o.error = ''; renderOverlay();
  const fail = (msg) => { if (!live()) return; o.busy = false; o.error = msg; renderOverlay(); };
  const done = (r) => { if (!live()) return; applyPayment(invoiceId, r, alloc); o.alloc = null; o.busy = false; o.error = ''; toast(r.fullyPaid || r.alreadyPaid ? 'Paid in full ✓' : 'Payment captured ✓'); renderOverlay(); };
  try {
    const c = IDX.customer.get(IDX.invoice.get(invoiceId)?.customerId);
    const pick = (o.selectedCardId && (customerCards(c).find((k) => k.id === o.selectedCardId) || verifiedBanks(c).find((k) => k.id === o.selectedCardId))) || defaultCard(c) || verifiedBanks(c)[0];   // §14b card or verified bank
    const r = await backendCall('stripeChargeInvoice', { invoiceId, amountCents, paymentMethodId: pick?.stripePmId || undefined });
    if (!live()) return;
    if (r && r.ok && (r.status === 'succeeded' || r.alreadyPaid)) { done(r); return; }
    if (r && r.ok && r.processing) {   // §14b ACH initiated — NOT paid yet; the invoice shows "processing" until it settles (check status to settle)
      const inv2 = IDX.invoice.get(invoiceId); if (inv2) { inv2.achProcessing = true; if (r.paymentIntentId) inv2.pendingPaymentIntentId = r.paymentIntentId; }
      o.alloc = null; o.busy = false; o.error = ''; toast('ACH payment initiated — it settles in a few business days.'); closeOverlay(); render(); return;
    }
    if (r && r.requiresAction && r.clientSecret) {
      const stripe = getStripe(); if (!stripe) { fail('Payment library not ready.'); return; }
      const { paymentIntent, error } = await stripe.confirmCardPayment(r.clientSecret);
      if (!live()) return;
      if (error) { fail(error.message || 'Authentication failed.'); return; }
      if (paymentIntent && paymentIntent.status === 'succeeded') {
        const f = await backendCall('stripeFinalizeInvoice', { invoiceId, paymentIntentId: r.paymentIntentId });
        if (!live()) return;
        if (f && f.ok) { done(f); return; }
        markChargeFailed(invoiceId); fail(friendlyPayErr(f)); return;   // real decline after 3DS (T3.2)
      }
      fail('Card authentication was not completed.'); return;   // ambiguous (auth abandoned) — not a decline
    }
    markChargeFailed(invoiceId); fail(friendlyPayErr(r));   // real decline (T3.2)
  } catch (e) { fail('Network error — try again.'); }   // network/timeout is UNKNOWN, never marked failed (spec §5.5)
}
// Refund the captured amount back to the card (full). Reduces amountPaid; a full
// refund flips the invoice to Refunded. The server is authoritative.
async function refundInvoiceFlow(invoiceId) {
  if (!canMoney()) { toast('Pay/Charge/Refund is Office/Admin only.'); return; }   // #552 audit item 4: defence-in-depth
  { const _i = IDX.invoice.get(invoiceId); if (_i && invoiceCollectionsActive(_i)) { toast('Blocked: this invoice is in Collections — recall it first.'); return; } }   // spec collections §7.7

  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  // §19b per-line / partial refund (#125) — GATED behind PARTIAL_REFUNDS_ENABLED. When OFF
  // we refund the whole invoice (amountCents omitted), today's safe behavior. When ON, the
  // refund gross + the PRE-TAX per-line split come from o.refundAlloc; we send amountCents and
  // merge the client-owned split into inv.refundAllocations via applyPayment.
  let amountCents = null, refundAlloc = null;
  if (PARTIAL_REFUNDS_ENABLED) {
    const rr = resolveRefund(inv, o);
    if (rr.gross <= 0.005) { o.error = 'Assign a refund to at least one line.'; return renderOverlay(); }
    amountCents = Math.round(rr.gross * 100); refundAlloc = rr.alloc;
  }
  // Cash/Check refund BY HAND (recordManualRefund, no Stripe); a card refunds the captured
  // charge via Stripe (stripeRefundInvoice). Either way the SERVER owns the money totals
  // (refunded / refundedAmount, sync-PROTECTED, #177); applyPayment keeps amountPaid so the
  // balance reads $0 and derives the status from inv.refunded. (#109/#117)
  const manual = /^cash$/i.test(inv.paymentMethod || '') || /^check/i.test(inv.paymentMethod || '');
  const action = manual ? 'recordManualRefund' : 'stripeRefundInvoice';
  const live = () => state.overlay === o;
  o.busy = true; o.error = ''; o.confirmRefund = false; renderOverlay();
  try {
    const r = await backendCall(action, amountCents != null ? { invoiceId, amountCents } : { invoiceId });
    if (!live()) return;
    if (r && r.ok) { applyPayment(invoiceId, r, null, refundAlloc); o.refundAlloc = null; o.busy = false; toast('Refunded ✓'); renderOverlay(); return; }
    o.busy = false; o.error = friendlyPayErr(r); renderOverlay();
  } catch (e) { if (live()) { o.busy = false; o.error = 'Network error — try again.'; renderOverlay(); } }
}
// Apply a server charge/refund result to the local invoice; status is derived from amountPaid.
// alloc (§19) = the pre-tax per-line split just charged → accumulate into inv.allocations;
// refundAlloc (§19b) = the pre-tax per-line split just refunded → accumulate into
// inv.refundAllocations. Both are client-owned + synced; the money totals from `r` are
// server-authoritative.
function applyPayment(invoiceId, r, alloc, refundAlloc) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const before = invoiceTotals(inv).status;
  if (r.amountPaid != null) inv.amountPaid = r.amountPaid;
  if (r.paid != null) inv.paid = r.paid;
  if (r.paidAt) inv.paidAt = r.paidAt;
  if (r.paymentMethod) inv.paymentMethod = r.paymentMethod;
  if (r.refunded != null) inv.refunded = r.refunded;
  if (r.refundedAmount != null) inv.refundedAmount = r.refundedAmount;
  if (r.locked != null) inv.locked = r.locked;
  if (alloc) { inv.allocations = inv.allocations || {}; Object.entries(alloc).forEach(([k, v]) => { inv.allocations[k] = (Number(inv.allocations[k]) || 0) + v; }); }
  if (refundAlloc) { inv.refundAllocations = inv.refundAllocations || {}; Object.entries(refundAlloc).forEach(([k, v]) => { inv.refundAllocations[k] = (Number(inv.refundAllocations[k]) || 0) + v; }); }
  if (inv.refunded) inv.allocations = {};   // a full refund releases every payment line assignment
  reindex('invoices', inv);
  // Phase 3 (T3.2) — a successful payment (card, ACH, cash, or check — applyPayment is the single
  // success handler for all of them) clears a failed-payment block ANYWHERE on the account (D11 /
  // Jac's Q3 call), not just on the invoice that originally declined. A refund is not a successful
  // payment, so it does NOT clear the flag.
  if (!r.refundedCents && inv.customerId) { const c = IDX.customer.get(inv.customerId); if (c && c.chargeFailedAt) { delete c.chargeFailedAt; reindex('customers', c); } }
  const after = invoiceTotals(inv).status;
  logAction(inv, r.refundedCents != null ? `Refunded ${money((r.refundedCents || 0) / 100)} — ${before} → ${after}` : `Payment — ${before} → ${after} (${r.paymentMethod || 'card'})`);
  render();
}
// Headless CASH / CHECK payment core (#109) — shared by the overlay handler AND Mr. Wrangler's
// recordPayment operation. The SERVER is authoritative (caps at the live balance, appends to payments[],
// audits the ledger); we apply its result via applyPayment. method is 'cash'|'check' ONLY — this NEVER
// charges a card or runs an ACH. Throws (with a friendly message) on failure so the caller can surface it.
async function postManualPayment({ invoiceId, amountCents, method, checkNum }) {
  // #552 audit item 4: defence-in-depth — the direct UI flow (recordManualPayment)
  // had no gate of its own; Mr. Wrangler's recordPayment action is already gated
  // upstream in wrValidatePlan, so canMoney() is still true there and this is a
  // no-op for that path, but now nothing can reach the backend call ungated.
  if (!canMoney()) throw new Error('Recording a payment is Office/Admin only.');
  const m = String(method || '').toLowerCase();
  if (m !== 'cash' && m !== 'check') throw new Error('Only cash or check can be recorded here.');   // belt-and-suspenders e-rail guard
  const r = await withTimeout(backendCall('recordManualPayment', { invoiceId, amountCents, method: m, checkNum: m === 'check' ? (checkNum || '') : '' }), 30000, 'Recording the payment');
  if (!r || !r.ok) throw new Error(friendlyPayErr(r));
  applyPayment(invoiceId, r);   // server is authoritative (amountPaid / paymentMethod / paidAt)
  return r;
}
// Record a manual CASH / CHECK payment (#109) — no Stripe. The figure is captured to
// the exact cent (no ceiling/rounding) and clamped at the outstanding balance so a
// payment can never overpay; partials just dial the amount down. amountPaid persists
// through the normal record sync, exactly like every other invoice field.
// Record a manual CASH / CHECK payment (#109) — no Stripe. The figure is captured to
// the exact cent and clamped at the outstanding balance so a payment can never overpay.
// The SERVER records it (recordManualPayment): invoice money fields (amountPaid,
// paymentMethod, paidAt, payments) are server-owned / sync-PROTECTED, so a client-side
// write gets stripped on sync and "reverts" on refresh (#bug). The backend is
// authoritative — it caps at the live balance, appends to payments[] and audits the
// ledger — exactly like a card charge; we apply its result via applyPayment.
async function recordManualPayment(invoiceId) {
  const o = state.overlay; if (!o || o.kind !== 'payment') return;
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  if (invoicePoBlocked(inv)) { o.error = 'PO required for this customer — add the PO # before recording a payment.'; return renderOverlay(); }   // PO gate — Block ALL: cash/check blocked too until a PO # is on the invoice
  const numEl = document.querySelector('.overlay .js-check-num'); if (numEl) o.checkNum = numEl.value.trim();   // survive the error re-render
  const t = invoiceTotals(inv);
  const amtEl = document.querySelector('.overlay .js-manual-amt');
  const entered = amtEl ? Number(amtEl.value) : NaN;
  if (!(entered > 0)) { o.error = 'Enter an amount greater than $0.'; return renderOverlay(); }
  const balCents = Math.round(t.balance * 100);
  if (balCents <= 0) { o.error = 'Nothing left to pay on this invoice.'; return renderOverlay(); }
  const payCents = Math.min(Math.round(entered * 100), balCents);   // exact cents, never over the balance
  const isCheck = o.method === 'check';
  const checkNum = (o.checkNum || '').trim();
  if (isCheck && !checkNum) { o.error = 'Enter the check number.'; return renderOverlay(); }
  const live = () => state.overlay === o;
  o.busy = true; o.error = ''; renderOverlay();
  try {
    const r = await postManualPayment({ invoiceId, amountCents: payCents, method: isCheck ? 'check' : 'cash', checkNum: isCheck ? checkNum : '' });
    if (!live()) return;
    o.busy = false; closeOverlay();
    toast(invoiceTotals(inv).balance <= 0.005 ? 'Paid in full ✓' : `${r.paymentMethod || 'Cash'} payment recorded ✓`);
  } catch (e) {
    if (live()) { o.busy = false; o.error = (e && e.rwTimeout) ? 'Timed out — try again.' : ((e && e.message) || 'Network error — try again.'); renderOverlay(); }
  }
}
// ── Invoice "Yard Log" PRINT / PDF (#109; reshaped to a kraft yard-log page 2026-07-08).
// A customer-facing document rendered into #print-root: line items GROUPED by rental
// (recent→oldest window), each group stamped with its window · duration · merge/extension
// provenance · per-rental subtotal; a grand subtotal; a machine glyph per unit line; a red
// BALANCE DUE + PAID stamp; a signature block; and a customer-safe Amendments log. The
// @media print rules swap the dark yard UI out and the browser dialog handles "Save as PDF".

/** "2 Days" · "2 Weeks" · "1 Month" from a day count (28d = 1 Month, matching the 4-Week
 *  rate; falls back to whole weeks then days). */
function prDuration(days) {
  if (days % 28 === 0) { const m = days / 28; return `${m} Month${m === 1 ? '' : 's'}`; }
  if (days % 7 === 0)  { const w = days / 7;  return `${w} Week${w === 1 ? '' : 's'}`; }
  return `${days} Day${days === 1 ? '' : 's'}`;
}
/** Provenance stamp for a rental group: "Merged from 216i" (lines carry a `fromInv` tag
 *  stamped at merge time) · "Extension of 216i" (a line's "Ext of NNN" tail, or the invoice's
 *  contOf when this is the covered rental) · "Extension" (a grow-in-place extension line). */
function prGroupProvenance(inv, r, gl) {
  const merged = gl.find((li) => li.fromInv);
  if (merged) return `Merged from ${invoiceShort(merged.fromInv)}`;
  for (const li of gl) { const m = /·\s*Ext of\s+(\S+)\s*$/i.exec(li.label || ''); if (m) return `Extension of ${m[1]}`; }
  if (inv.contOf && r && inv.covOf === r.rentalId) return `Extension of ${invoiceShort(inv.contOf)}`;
  if (gl.some((li) => li.kind === 'extension')) return 'Extension';
  return '';
}
/** Group an invoice's line items by rental, newest window first (manual / unlinked lines
 *  fall to a trailing "Additional charges" group). */
function invoicePrintGroups(inv) {
  const map = new Map(), order = [];
  (inv.lineItems || []).forEach((li) => {
    const r = li.ref ? IDX.rental.get(li.ref) : null;
    const key = r ? r.rentalId : '__other';
    if (!map.has(key)) { map.set(key, { r, key, lines: [] }); order.push(key); }
    map.get(key).lines.push(li);
  });
  const groups = order.map((key) => {
    const g = map.get(key), r = g.r;
    const start = r ? r.startDate : '', end = r ? r.endDate : '';   // unlinked "Additional charges" get no window/duration
    const days = (parseISO(start) && parseISO(end)) ? Math.max(1, dayDiff(parseISO(start), parseISO(end))) : 0;
    return {
      key, r, isOther: key === '__other', start,
      title: (key === '__other') ? 'Other' : 'Rental',
      window: (start && end) ? `${fmtShortDate(start)} – ${fmtShortDate(end)}` : '',
      dur: days ? prDuration(days) : '',
      prov: (key === '__other') ? '' : prGroupProvenance(inv, r, g.lines),
      subtotal: g.lines.reduce((a, li) => a + (Number(li.amount) || 0), 0),
      lines: g.lines,
    };
  });
  groups.sort((a, b) => a.isOther ? 1 : b.isOther ? -1 : (a.start < b.start ? 1 : a.start > b.start ? -1 : 0));
  return groups;
}
/** One printed line row → { icon, name, cat, meta }. A unit line shows its glyph + name +
 *  CATEGORY only (the per-day rate/qty is dropped — the card header now carries the window +
 *  duration). Transport keeps its leg descriptor; a manual line shows its plain label. */
function prLineParts(li) {
  let rest = String(li.label || '').replace(/\s*·\s*Ext of\s+\S+\s*$/i, '').replace(/\s*·\s*Extension\s*→.*$/i, '');
  if (li.kind === 'transport') {
    const r = li.ref ? IDX.rental.get(li.ref) : null;
    const eu = (r && li.unitId) ? unitEntry(r, li.unitId) : null;
    const type = (eu && eu.transportType) || (r && r.transportType) || rest.replace(/^Transport\s*·\s*/i, '');
    const addr = (eu && eu.deliveryAddress) || (r && r.deliveryAddress) || '';
    const miles = Number((eu && eu.transportMiles) || (r && r.transportMiles) || 0);
    return { icon: I.truck, name: 'Transport', cat: '', meta: [type, addr, miles ? `${miles} mi` : ''].filter(Boolean).join(' · ') };
  }
  const u = li.unitId ? IDX.unit.get(li.unitId) : null;
  if (u) {
    const cat = IDX.category.get(u.categoryId);
    return { icon: categoryIconFor(cat && cat.name), name: u.name, cat: (cat && cat.name) || '', meta: '' };
  }
  return { icon: '', name: rest, cat: '', meta: '' };
}
/** Customer-safe amendment logs — SEPARATED: { invoiceLog, rentalLog }. Each is the record's
 *  actions scrubbed of internal ops detail (staff names via `by`, pricing locks, Mr. Wrangler,
 *  card/ACH, mechanic/GPS), internal-but-relevant wording translated to plain language, sorted
 *  MOST RECENT → oldest. rentalLog entries carry the rental name (which unit(s)). */
function invoiceAmendments(inv) {
  const DENY = /pricing (un)?locked|mr\.?\s*wrangler|added by|••|\bach\b|\bcard\b|mechanic|assigned|\bgps\b|\bhours\b|collections?|recall|aging|blacklist/i;
  // Billing / invoice-lifecycle events are logged onto the RENTAL too (createInvoiceForRental,
  // the extension re-price, void/unlink), so they used to surface under Rental Log — an
  // "Invoice NNN created" line reading like invoice history in the rental column (Jac 2026-07-17).
  // Split by SUBJECT, not by which record stores the action: a rental action whose topic is the
  // invoice moves to Invoice Log. Matched on the RAW text — scrub rewrites the wording below.
  const INV_TOPIC = /^(Invoice |Continuation invoice |Extension |Added to invoice |Unlinked —)/i;
  const scrub = (a, rname) => {
    let text = String(a.text || '');
    if (!text || DENY.test(text)) return null;
    text = text
      .replace(/\s*[,—-]\s*by \S+\s*$/i, '')   // strip any trailing "— by <role>" staff attribution (never on a customer doc)
      .replace(/Merged in invoice\s+\S+.*$/i, 'Combined with a prior ticket')
      .replace(/Continuation (of|invoice)\b.*$/i, 'Continued on a new ticket (28-day billing)')
      .replace(/Transport type →/i, 'Transport set to');
    return { when: a.when, clock: a.clock || '', seq: a.seq || 0, text, rname: rname || '' };
  };
  const recent = (x, y) => (x.when < y.when ? 1 : x.when > y.when ? -1 : (y.seq - x.seq));   // most recent → oldest
  const invoiceLog = (inv.actions || []).map((a) => scrub(a)).filter(Boolean);
  const rentalLog = [];
  (inv.rentalIds || []).map((id) => IDX.rental.get(id)).filter(Boolean).forEach((r) => {
    const rname = rentalUnitsLabel(r) || r.rentalName || '';
    (r.actions || []).forEach((a) => {
      const s = scrub(a, rname); if (!s) return;
      (INV_TOPIC.test(String(a.text || '')) ? invoiceLog : rentalLog).push(s);   // billing event → Invoice Log, physical rental event → Rental Log
    });
  });
  invoiceLog.sort(recent);
  rentalLog.sort(recent);
  return { invoiceLog, rentalLog };
}
/** Invoice status → the print doc's accent state: green (paid), yellow (open / not yet due),
 *  red (past due). Drives the date stamp, hazard stripe, Balance Due and the Paid stamp. */
function prInvoiceInk(inv, t) {
  const tt = t || invoiceTotals(inv);
  if (inv.voided || tt.status === 'Voided') return 'is-refunded';       // voided = off the books (gray), NOT paid-green
  if (inv.refunded || tt.status === 'Refunded') return 'is-refunded';   // settled by refund, NOT paid-green (#552-r2)
  if (tt.balance <= 0.005) return 'is-paid';
  return /^(Late|Collections)/.test(tt.status) ? 'is-due' : 'is-open';
}
/* §12.5 / §3.3 — the ONE invoice document builder. Both printInvoice (into #print-root)
   and the embedded Customer-Details expand render from this, so screen and printout can
   never diverge. The DEFAULT output (no opts) is BYTE-IDENTICAL to the print doc. `opts
   .interactive` — used ONLY by the on-screen inline sheet, NEVER for #print-root —
   additively augments the SAME sheet with line-item source links (R2) + an inline PO edit;
   because print never sets it, the printed bytes are unchanged. */
function invoiceDocHtml(inv, opts = {}) {
  const interactive = !!opts.interactive;
  const t = invoiceTotals(inv);
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  const groups = invoicePrintGroups(inv);
  const refunded = t.refunded || t.status === 'Refunded';
  const voided = inv.voided || t.status === 'Voided';   // a $0 off-the-books record — never a Paid stamp
  const refAmt = Number(inv.refundedAmount) || 0;
  const paid = t.balance <= 0.005 && t.total > 0 && !refunded && !voided;   // a refunded/voided invoice reads $0 balance but is NOT "Paid in Full" (#552-r2)
  const ink = prInvoiceInk(inv, t);   // is-paid (green) / is-open (yellow) / is-due (red) / is-refunded (gray)
  const bigDate = (fmtShortDate(inv.date) || '').toUpperCase();
  const brandName = companyName().replace(/([a-z])([A-Z])/g, '$1 $2');   // "JacRentals" → "Jac Rentals" (proper case, spaced)
  const custPhoto = cust ? latestCustomerSelfie(cust) : '';

  // Each rental → a soft card with a single-line header: the bold title FIRST, then its window ·
  // duration · provenance, and the per-rental subtotal pinned right; the unit lines sit inside.
  // `interactive` (inline sheet only) additively appends a source-link ↗ on rental/WO lines.
  const cardHtml = (g) => {
    const lines = g.lines.map((li) => {
      const p = prLineParts(li);
      const src = (interactive && li.ref && (li.kind === 'rental' || li.kind === 'WO'))
        ? ` <span class="pr-line-src" data-r="R2" data-pill-card="${li.kind === 'WO' ? 'workOrders' : 'rentals'}" data-pill-rec="${esc(li.ref)}" data-tip="Open the source ${li.kind === 'WO' ? 'work order' : 'rental'}">↗</span>`
        : '';
      return `<div class="pr-line"><span class="pr-desc">${p.icon ? `<span class="pr-ic">${p.icon}</span>` : '<span class="pr-ic"></span>'}<span class="pr-txt"><span class="pr-nm">${esc(p.name)}${src}</span>${p.cat ? `<span class="pr-cat">${esc(p.cat)}</span>` : ''}${p.meta ? `<span class="pr-mt">${esc(p.meta)}</span>` : ''}</span></span><span class="pr-amt">${money2(Number(li.amount) || 0)}</span></div>`;
    }).join('');
    const meta = `${g.window ? `<span>${esc(g.window)}</span>` : ''}${g.dur ? `<span>${esc(g.dur)}</span>` : ''}${g.prov ? `<span class="pr-prov">${esc(g.prov)}</span>` : ''}`;
    return `<section class="pr-card">
      <header class="pr-card-h"><span class="pr-card-t">${esc(g.title)}</span>${meta ? `<span class="pr-card-m">${meta}</span>` : ''}<span class="pr-card-sub">${money2(g.subtotal)}</span></header>
      <div class="pr-card-lines">${lines}</div>
    </section>`;
  };
  const groupsHtml = groups.length ? groups.map(cardHtml).join('') : '<div class="pr-empty">No line items.</div>';

  const paymentRows = (inv.payments || []).length
    ? (inv.payments || []).map((pmt) => {
        const when = pmt.at ? esc(fmtShortDate(pmt.at)) : '';
        const method = pmt.type === 'cash' ? 'Cash'
          : pmt.type === 'check' ? ('Check' + (pmt.checkNum ? ' #' + esc(String(pmt.checkNum)) : ''))
          : pmt.type === 'ach-pending' ? 'ACH (pending)'
          : pmt.type === 'charge' ? 'Card'
          : esc(String(pmt.type || 'Payment'));
        return `<div><span>Paid${when ? ' · ' + when : ''} · ${method}</span><span>${money2((Number(pmt.amountCents) || 0) / 100)}</span></div>`;
      }).join('')
    : (t.paid ? `<div><span>Paid${inv.paymentMethod ? ' · ' + esc(inv.paymentMethod) : ''}</span><span>${money2(t.paid)}</span></div>` : '');

  const { invoiceLog, rentalLog } = invoiceAmendments(inv);
  const logRow = (a, withName) => `<div class="pr-am-row"><span class="pr-am-when">${esc(fmtShortDate(a.when))}${a.clock ? ' · ' + esc(a.clock) : ''}</span><span class="pr-am-tx">${esc(a.text)}${withName && a.rname ? ` <em>· ${esc(a.rname)}</em>` : ''}</span></div>`;
  const logCol = (title, items, withName) => `<div class="pr-log"><div class="pr-log-h">${title}</div>${items.length ? items.map((a) => logRow(a, withName)).join('') : '<div class="pr-am-empty">No entries.</div>'}</div>`;

  // PO meta row — print shows it only when set; the inline sheet always renders it with an edit control.
  const poRow = interactive
    ? `<div><span class="pr-k">PO</span><span class="pr-v">${inv.po ? esc(inv.po) : '<span class="muted">—</span>'} <span class="pr-po-edit inline-edit" data-edit="invoicePO" data-rec="${esc(inv.invoiceId)}" data-tip="Edit PO number">Edit</span></span></div>`
    : (inv.po ? `<div><span class="pr-k">PO</span><span class="pr-v">${esc(inv.po)}</span></div>` : '');

  return `
    <div class="pr-doc ${ink}"${interactive ? ` data-inv="${esc(inv.invoiceId)}"` : ''}>
      <div class="pr-head">
        <div class="pr-brandwrap"><img class="pr-logo" src="assets/jac-rentals-logo.jpg" alt="${esc(brandName)}" /><div><div class="pr-brand">${esc(brandName)}</div><div class="pr-sub">${esc(companyTagline())}</div></div></div>
        <div class="pr-datestamp">${esc(bigDate)}</div>
      </div>
      <div class="pr-hazard" aria-hidden="true"></div>
      <div class="pr-meta">
        <div><span class="pr-k">Invoice</span><span class="pr-v">${esc(inv.invoiceId)}</span></div>
        <div><span class="pr-k">Bill to</span><span class="pr-v">${esc(cust ? cust.name : '—')}</span></div>
        <div><span class="pr-k">Created</span><span class="pr-v">${esc(fmtShortDate(inv.date) || '—')}</span></div>
        <div><span class="pr-k">Due</span><span class="pr-v">${esc(inv.dueDate ? fmtShortDate(inv.dueDate) : '—')}</span></div>
        ${poRow}
        ${inv.contOf ? `<div><span class="pr-k">Continuation of</span><span class="pr-v">${esc(invoiceShort(inv.contOf))} (28-day billing split)</span></div>` : ''}
      </div>
      <div class="pr-groups">${groupsHtml}</div>
      <div class="pr-summary">
        <div class="pr-cust">
          ${custPhoto ? `<img class="pr-cust-photo" src="${esc(custPhoto)}" alt="" />` : ''}
          ${paid ? `<div class="pr-stamp${custPhoto ? ' on-photo' : ''}" aria-hidden="true">Paid in Full</div>` : voided ? `<div class="pr-stamp${custPhoto ? ' on-photo' : ''}" aria-hidden="true">Voided</div>` : refunded ? `<div class="pr-stamp${custPhoto ? ' on-photo' : ''}" aria-hidden="true">Refunded</div>` : ''}
        </div>
        <div class="pr-tot">
          <div><span>Grand Subtotal</span><span>${money2(t.subtotal)}</span></div>
          <div><span>Tax${t.exempt ? ' (exempt)' : ` (${(TAX_RATE * 100).toFixed(2)}%)`}</span><span>${t.exempt ? '—' : money2(t.tax)}</span></div>
          <div class="pr-big"><span>Total</span><span>${money2(t.total)}</span></div>
          ${paymentRows}
          ${refunded && refAmt > 0 ? `<div class="pr-refund"><span>Refunded</span><span>-${money2(refAmt)}</span></div>` : ''}
          <div class="pr-due"><span>Balance Due</span><span>${money2(t.balance)}</span></div>
        </div>
      </div>
      <div class="pr-logs">
        ${logCol('Invoice Log', invoiceLog, false)}
        ${logCol('Rental Log', rentalLog, true)}
      </div>
    </div>`;
}
function printInvoice(invoiceId) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  let host = document.getElementById('print-root');
  if (!host) { host = document.createElement('div'); host.id = 'print-root'; document.body.appendChild(host); }
  host.innerHTML = invoiceDocHtml(inv);   // print path: no opts → byte-identical to the pretty print doc
  document.documentElement.classList.add('printing');   // full-bleed: kraft rides the root canvas so it fills every sheet edge
  document.body.classList.add('printing');
  const cleanup = () => { document.documentElement.classList.remove('printing'); document.body.classList.remove('printing'); window.removeEventListener('afterprint', cleanup); };
  window.addEventListener('afterprint', cleanup);
  window.print();
}
/* Copy the on-screen invoice sheet to the clipboard as a PNG (right-click → Copy as image,
   Jac 2026-07-17). Library-free rasterization: clone the live .pr-doc, inline every element's
   COMPUTED style (so no stylesheet / CSS-var resolution is needed inside the SVG), data-URI the
   images so the canvas never taints, wrap the XHTML in an <svg><foreignObject>, paint it to a
   canvas, hand the PNG blob to the clipboard. The blob is produced INSIDE a ClipboardItem promise
   so the write still counts as the user's gesture on Safari. Fonts loaded via @font-face may fall
   back to a system face inside the SVG (a known foreignObject limit) — layout/colors are faithful,
   the typeface may not be; on any failure we fall back to a clear toast pointing at Save-as-PDF. */
function copyInvoiceImage(invoiceId) {
  const fail = () => toast('Couldn’t copy the image on this browser — use 🖨 Save PDF instead.');
  if (!(navigator.clipboard && window.ClipboardItem)) return fail();   // no clipboard-image support (e.g. older Firefox) → point at Save-as-PDF, don't waste a render
  // Render INSIDE the ClipboardItem promise so the write still counts as the user's gesture on Safari.
  navigator.clipboard.write([new ClipboardItem({ 'image/png': renderInvoicePng(invoiceId) })])
    .then(() => toast('🖼 Invoice copied — paste it into a message, chat, or doc.'))
    .catch(fail);
}
async function renderInvoicePng(invoiceId) {
  const doc = [...document.querySelectorAll('.pr-doc[data-inv]')].find((d) => d.dataset.inv === invoiceId);
  if (!doc) throw new Error('invoice sheet not on screen');
  const rect = doc.getBoundingClientRect();
  const W = Math.ceil(rect.width), H = Math.ceil(rect.height);
  const clone = doc.cloneNode(true);
  inlineComputedStyles(doc, clone);   // resolve classes + CSS vars to concrete values
  await inlineDocImages(clone);       // <img src> → data: so drawImage doesn't taint the canvas
  clone.style.boxShadow = 'none'; clone.style.borderRadius = '0'; clone.style.margin = '0'; clone.style.maxWidth = 'none'; clone.style.width = W + 'px';
  clone.setAttribute('xmlns', 'http://www.w3.org/1999/xhtml');
  const xhtml = new XMLSerializer().serializeToString(clone);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${W}" height="${H}"><foreignObject x="0" y="0" width="${W}" height="${H}">${xhtml}</foreignObject></svg>`;
  const img = await new Promise((res, rej) => { const im = new Image(); im.onload = () => res(im); im.onerror = () => rej(new Error('svg render failed')); im.src = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg); });
  const dpr = Math.min(window.devicePixelRatio || 1, 2);   // cap the scale so a retina phone doesn't mint a giant canvas
  const canvas = document.createElement('canvas');
  canvas.width = Math.max(1, W * dpr); canvas.height = Math.max(1, H * dpr);
  const cx = canvas.getContext('2d'); cx.scale(dpr, dpr);
  const bg = getComputedStyle(doc).backgroundColor;
  cx.fillStyle = (bg && bg !== 'rgba(0, 0, 0, 0)') ? bg : '#f7f2ea';   // kraft fallback if the doc bg is transparent
  cx.fillRect(0, 0, W, H);
  cx.drawImage(img, 0, 0);
  return await new Promise((res, rej) => canvas.toBlob((b) => (b ? res(b) : rej(new Error('encode failed'))), 'image/png'));
}
// Deep-copy each element's computed style onto the clone (index-aligned — cloneNode preserves
// structure). Concrete values mean the SVG needs no stylesheet or --var lookups.
function inlineComputedStyles(src, dst) {
  const cs = getComputedStyle(src);
  let s = '';
  for (let i = 0; i < cs.length; i++) { const p = cs[i]; s += `${p}:${cs.getPropertyValue(p)};`; }
  dst.setAttribute('style', s);
  const sc = src.children, dc = dst.children;
  for (let i = 0; i < sc.length; i++) if (dc[i]) inlineComputedStyles(sc[i], dc[i]);
}
// Same-origin images (logo, customer selfie) → data URIs, so the rasterized canvas isn't tainted
// (a tainted canvas can't be read back to a blob). An unfetchable image is dropped, not fatal.
async function inlineDocImages(root) {
  await Promise.all([...root.querySelectorAll('img')].map(async (im) => {
    const src = im.getAttribute('src') || '';
    if (!src || src.startsWith('data:')) return;
    try {
      const b = await (await fetch(src)).blob();
      im.setAttribute('src', await new Promise((res) => { const fr = new FileReader(); fr.onload = () => res(fr.result); fr.readAsDataURL(b); }));
    } catch (e) { im.removeAttribute('src'); }
  }));
}
// Plain-text quote summary for an emailed quote — mailto can't carry a PDF attachment,
// so we inline the same figures the print doc shows (§12.5 line items + totals).
function invoiceQuoteSummary(inv) {
  const t = invoiceTotals(inv);
  const lines = (inv.lineItems || []).map((li) => `  • ${li.label} — ${money2(Number(li.amount) || 0)}`).join('\n')
    || '  • (no line items yet)';
  return [
    `Quote ${inv.invoiceId} from ${companyName()}`, '',
    lines, '',
    `Subtotal: ${money2(t.subtotal)}`,
    `Tax${t.exempt ? ' (exempt)' : ` (${(TAX_RATE * 100).toFixed(2)}%)`}: ${t.exempt ? '—' : money2(t.tax)}`,
    `Total: ${money2(t.total)}`, '',
    'Thank you for your business — much obliged.',
  ].join('\n');
}
// Email a quote — SERVER send through the comms pipe (spec D6), with the D7 FROM picker:
// when the shop has more than one connected address (send-as aliases, enumerated server-
// side), the operator picks which one it goes out as; the server validates the choice.
// Demo/#local (no backend password) keeps the old mailto: deep-link.
let _commsAliases = null;   // fetched once per session; server-authoritative
async function commsAliasList() {
  if (_commsAliases) return _commsAliases;
  try { const r = await backendCall('commsAliases'); if (r && r.ok && Array.isArray(r.aliases) && r.aliases.length) _commsAliases = r.aliases; } catch (e) {}
  return _commsAliases || [];
}
async function emailQuoteSend(invoiceId, from) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  toast('Sending email…');
  let r; try { r = await backendCall('sendCustomerMessage', { channel: 'email', entity: 'invoice', recId: inv.invoiceId, customerId: inv.customerId, template: 'quote', from: from || '' }); }
  catch (e) { r = { ok: false, reason: 'network' }; }
  if (r && r.ok) {
    logAction(inv, `Emailed quote to ${r.maskedTo || 'customer'}${r.fromUsed ? ` (from ${r.fromUsed})` : ''}`);
    render();
    toast(`Quote emailed to ${r.maskedTo || 'the customer'}.`);
    return;
  }
  const why = {
    'no-email': 'No email on file — add one on the account.',
    'opted-out': 'This customer has opted out of email — hard stop.',
    'cap': 'Daily send cap reached — raise SMS_DAILY_CAP if this run is legit.',
    'isolation': 'Record/customer mismatch — reload and try again.',
    'provider': 'The mail send failed server-side — if this is the first email ever, the backend still needs its one-time Gmail permission (editor → Run → authorize).',
    'network': 'Couldn’t reach the backend — try again.',
  }[r && r.reason] || 'Email didn’t send — try again.';
  toast(why);
}
async function sendInvoiceEmail(invoiceId, anchorEl) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  if (!cust || !cust.email) { toast('No email on file for this customer.'); return; }   // guard — button is disabled, this is belt-and-suspenders
  if (invoicePoBlocked(inv)) { toast('PO required for this customer — add the PO # before sending.'); return; }   // PO gate — hard-block the send until a PO # is on the invoice
  if (!backendPassword) {   // demo/offline — the pre-pipe mailto path, unchanged
    const subject = `Quote from ${companyName()} – ${inv.invoiceId}`;
    window.location.href = `mailto:${encodeURIComponent(cust.email)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(invoiceQuoteSummary(inv))}`;
    logAction(inv, `Emailed quote to ${cust.email}`);
    render();
    toast(`Opening email to ${cust.email}…`);
    return;
  }
  const aliases = await commsAliasList();
  if (aliases.length > 1 && anchorEl && document.contains(anchorEl)) {   // D7 — pick which connected address it goes out as
    const html = aliases.map((a) => `<button class="dd-item js-email-from-pick" data-rec="${esc(invoiceId)}" data-from="${esc(a)}">${esc(a)}</button>`).join('');
    openDropdown(anchorEl, html, { align: 'left' });
    return;
  }
  return emailQuoteSend(invoiceId, aliases[0] || '');
}
// Text a quote — SERVER send via the comms pipe (spec comms D1/D2: sendCustomerMessage →
// Mocean adapter; recipient/body/gates all resolved server-side — the client passes only
// ids + a template name, never a `to` or a body). Demo/#local mode (no backend password)
// keeps the old device deep-link so offline demos still work.
async function sendInvoiceText(invoiceId) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  const cust = inv.customerId ? IDX.customer.get(inv.customerId) : null;
  if (!cust || !cust.phone) { toast('No phone on file for this customer.'); return; }
  if (invoicePoBlocked(inv)) { toast('PO required for this customer — add the PO # before sending.'); return; }   // PO gate — hard-block the send until a PO # is on the invoice
  if (!backendPassword) {   // demo/offline — the pre-pipe deep-link path, unchanged
    const t = invoiceTotals(inv);
    const first = cust.firstName || (cust.name || '').trim().split(/\s+/)[0] || 'there';
    const yard = companyPhone();
    const msg = `Hi ${first}, your quote from ${companyName()} is ready – ${money2(t.total)} – reply or call us${yard ? ' at ' + yard : ''}.`;
    const tel = String(cust.phone).replace(/[^0-9+]/g, '');
    window.location.href = `sms:${tel}?&body=${encodeURIComponent(msg)}`;   // `?&body=` is the cross-platform (iOS + Android) separator
    logAction(inv, `Texted quote to ${cust.phone}`);
    render();
    toast(`Opening text to ${cust.phone}…`);
    return;
  }
  toast('Sending text…');
  let r; try { r = await backendCall('sendCustomerMessage', { entity: 'invoice', recId: inv.invoiceId, customerId: inv.customerId, template: 'quote' }); }
  catch (e) { r = { ok: false, reason: 'network' }; }
  if (r && r.ok) {
    logAction(inv, `SMS quote sent to ${r.maskedTo || 'customer'}`);
    render();
    toast(`Quote texted to ${r.maskedTo || 'the customer'}.`);
    return;
  }
  const why = {   // server refusal → say what's wrong and where to fix it (R19 voice)
    'no-phone': 'No phone on file — add one on the account.',
    'opted-out': 'This customer has opted out of texts — hard stop.',
    'not-configured': 'SMS isn’t wired yet — Mocean keys go in the backend Script Properties.',
    'cap': 'Daily text cap reached — raise SMS_DAILY_CAP if this run is legit.',
    'quiet-hours': 'Quiet hours (8pm–8am) — the message can go out in the morning.',
    'isolation': 'Record/customer mismatch — reload and try again.',
    'provider': 'Mocean rejected the send — check the number and Mocean balance.',
    'network': 'Couldn’t reach the backend — try again.',
  }[r && r.reason] || 'Text didn’t send — try again.';
  toast(why);
}
// Lock (seal pricing) or unlock an invoice via the backend (Office/Admin).
async function lockInvoiceFlow(invoiceId, lock) {
  const inv = IDX.invoice.get(invoiceId); if (!inv) return;
  try {
    const r = await backendCall(lock ? 'stripeLockInvoice' : 'stripeUnlockInvoice', { invoiceId });
    if (r && r.ok) { inv.locked = !!r.locked; reindex('invoices', inv); logAction(inv, r.locked ? 'Pricing locked' : 'Pricing unlocked'); render(); toast(r.locked ? 'Pricing locked 🔒' : 'Unlocked for editing'); }
    else toast(friendlyPayErr(r));
  } catch (e) { toast('Couldn’t reach the backend — try again.'); }
}

